import math

def adaboost_fit(X, y, n_clf):
    n_samples = len(X)
    n_features = len(X[0])
    w = [1.0 / n_samples] * n_samples
    clfs = []

    for _ in range(n_clf):
        best_error = float('inf')
        best_clf = {}

        for feature_idx in range(n_features):
            feature_vals = [X[i][feature_idx] for i in range(n_samples)]
            unique_vals = sorted(set(feature_vals))
            # Use midpoints between sorted unique values as thresholds
            thresholds = []
            for i in range(len(unique_vals) - 1):
                thresholds.append((unique_vals[i] + unique_vals[i + 1]) / 2.0)
            if not thresholds:
                thresholds = [unique_vals[0]]

            for threshold in thresholds:
                for polarity in [1, -1]:
                    predictions = []
                    for val in feature_vals:
                        if polarity * val < polarity * threshold:
                            predictions.append(-1)
                        else:
                            predictions.append(1)

                    # Weighted error: sum of weights where prediction != label
                    error = sum(w[i] for i in range(n_samples) if predictions[i] != y[i])

                    if error < best_error:
                        best_error = error
                        # Clamp error to avoid log(0)
                        clamped_error = max(error, 1e-10)
                        alpha = 0.5 * math.log((1.0 - clamped_error) / clamped_error)
                        best_clf = {
                            'feature_idx': feature_idx,
                            'threshold': threshold,
                            'polarity': polarity,
                            'alpha': alpha,
                            'predictions': predictions[:]
                        }

        alpha = best_clf['alpha']
        predictions = best_clf['predictions']

        # Update weights: w_i *= exp(-alpha * y_i * h(x_i))
        new_w = [
            w[i] * math.exp(-alpha * y[i] * predictions[i])
            for i in range(n_samples)
        ]
        # Normalize weights so they sum to 1
        total = sum(new_w)
        w = [wi / total for wi in new_w]

        # Store classifier without cached predictions to keep it lightweight
        clfs.append({
            'feature_idx': best_clf['feature_idx'],
            'threshold': best_clf['threshold'],
            'polarity': best_clf['polarity'],
            'alpha': best_clf['alpha']
        })

    return clfs


def adaboost_predict(X, clfs):
    """Helper: use fitted classifiers to predict."""
    n_samples = len(X)
    final_preds = [0.0] * n_samples
    for clf in clfs:
        fi, thresh, pol, alpha = (
            clf['feature_idx'], clf['threshold'],
            clf['polarity'], clf['alpha']
        )
        for i in range(n_samples):
            val = X[i][fi]
            pred = -1 if pol * val < pol * thresh else 1
            final_preds[i] += alpha * pred
    return [1 if v >= 0 else -1 for v in final_preds]
